const o=document.querySelectorAll(".reveal");if(o.length){const e=new IntersectionObserver(t=>{t.forEach(r=>{r.isIntersecting&&(r.target.classList.add("is-visible"),e.unobserve(r.target))})},{threshold:.15});o.forEach(t=>e.observe(t))}const n=document.querySelector(".menu-toggle"),s=document.querySelectorAll(".nav");n?.addEventListener("click",()=>{const e=n.getAttribute("aria-expanded")==="true";n.setAttribute("aria-expanded",String(!e)),s.forEach(t=>t.classList.toggle("nav-open",!e))});
